const files = $input.first().json;
const existingSlugs = Array.isArray(files)
  ? files.filter(f => f.name.endsWith('.md')).map(f => f.name.replace('.md', ''))
  : [];
return [{ json: { existingSlugs, existingTopics: existingSlugs.map(s => s.replace(/-/g, ' ')) } }];

const response = $input.first().json;
let topicData;
try {
  const text = response.message?.content || response.text || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  topicData = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch (e) {
  topicData = {
    topic: 'Mediterranean Garden Design Tips',
    targetKeyword: 'mediterranean garden design cyprus',
    secondaryKeywords: ['cyprus landscaping ideas', 'luxury garden paphos'],
    suggestedTitle: 'Mediterranean Garden Design Tips for Cyprus Homes',
    slug: 'mediterranean-garden-design-tips-cyprus',
    category: 'Design Inspiration',
    season: 'year-round',
    searchTerms: ['mediterranean garden', 'cyprus landscaping', 'garden design'],
    faqQuestions: ['How to design a Mediterranean garden?', 'What plants grow best in Cyprus?']
  };
}
return [{ json: topicData }];

const topicData = $('Parse Topic JSON').first().json;
const response = $input.first().json;
let markdown = response.message?.content || response.text || '';

// Clean up any code block wrappers
markdown = markdown.replace(/^```(?:markdown)?\n?/, '').replace(/\n?```$/, '').trim();

// Ensure it starts with frontmatter
if (!markdown.startsWith('---')) {
  markdown = '---\n' + markdown;
}

return [{
  json: {
    ...topicData,
    markdown: markdown,
    fileName: `${topicData.slug}.md`,
    filePath: `src/content/blog/${topicData.slug}.md`
  }
}];

const topicData = $('Prepare Blog Content').first().json;
let imageUrl = '';
let imageCredit = '';

// Try Unsplash first — pick the highest quality landscape image
try {
  const unsplash = $('Search Unsplash').first().json;
  if (unsplash.results && unsplash.results.length > 0) {
    // Prefer images with good dimensions for hero (wide landscape)
    const best = unsplash.results.find(r => r.width > r.height * 1.4) || unsplash.results[0];
    imageUrl = best.urls.regular;
    imageCredit = `Photo by ${best.user.name} on Unsplash`;
  }
} catch (e) {}

// Fallback to Pexels
if (!imageUrl) {
  try {
    const pexels = $('Search Pexels').first().json;
    if (pexels.photos && pexels.photos.length > 0) {
      const best = pexels.photos.find(p => p.width > p.height * 1.4) || pexels.photos[0];
      imageUrl = best.src.large2x || best.src.large;
      imageCredit = `Photo by ${best.photographer} on Pexels`;
    }
  } catch (e) {}
}

if (!imageUrl) {
  imageUrl = '';
  imageCredit = 'Green Planet Gardening';
}

return [{
  json: {
    ...topicData,
    imageUrl,
    imageCredit
  }
}];
